content:
// Windows builds are signed via Azure Trusted Signing (see signWindows() above
// and .github/workflows/publish.yml build-electron job which sets
// AZURE_TRUSTED_SIGNING_* env vars and verifies Authenticode signatures in CI).
// No legitimate reason to skip update signature verification — builds are properly
// signed on beta/prod channels (dev channel has no publish config so no auto-update).
win: {
  icon: `resources/icons/icon.ico`,
  signtoolOptions: {
    sign: signWindows,
  },
  target: ["nsis"],
  verifyUpdateCodeSignature: true,
},
